        "get_artifact",
        "get_chunk",
        "get_claim",
        "get_conclusion",
        "get_embedding_vector",
        "get_drift_event",
        "list_claim_ids",
        "list_conclusions",
        "list_chunks_for_artifact",
        "list_drift_events",
        "get_temporal_cut",
        "list_outcomes_for_cut",
    })

